const eventId = Number($('Vars').first().json.event_id);
const resp = $input.first().json;
const sessions = resp.data ?? [];
return sessions
  .filter(s => Number(s.event?.id) === eventId)
  .map(s => ({
    json: {
      session_id: s.id,
      session_name: s.name,
      event_id: s.event?.id,
      event_name: s.event?.name,
      on_sale: !!s.on_sale,
      sold_out: !!s.sold_out
    }
  }));

const eventId = Number($('Vars').first().json.event_id);
const sessions = $('Filter by event_id').all();
const responses = $input.all();

const out = [];
for (let i = 0; i < responses.length; i++) {
  const avail = responses[i].json;
  const sess  = sessions[i]?.json ?? {};
  const sessionId = avail.id ?? sess.session_id;
  const eventName = sess.event_name ?? null;

  for (const sec of avail.sectors ?? []) {
    let available = 0;
    let total = 0;
    for (const pt of sec.price_types ?? []) {
      available += pt.availability?.available ?? 0;
      total     += pt.availability?.total ?? 0;
    }
    if (available > 0) {
      out.push({ json: {
        event_id: eventId,
        session_id: sessionId,
        event_name: eventName,
        grada_id: sec.id,
        grada_name: sec.name,
        grada_code: sec.code ?? null,
        available,
        total
      }});
    }
  }
}
return out;

// For each grada with availability, find Mailchimp subscribers whose tags
// include event:<id>, grada:<id> and source:avisame.
const members = $('Aggregate members').first().json.members ?? [];
const gradas  = $input.all();
const wantSource = 'source:avisame';

const out = [];
for (const g of gradas) {
  const ctx = g.json;
  const wantEvent = 'event:' + ctx.event_id;
  const wantGrada = 'grada:' + ctx.grada_id;
  for (const m of members) {
    if (m.status !== 'subscribed') continue;
    const tagNames = (m.tags ?? []).map(t => t.name);
    if (!tagNames.includes(wantEvent)) continue;
    if (!tagNames.includes(wantGrada)) continue;
    if (!tagNames.includes(wantSource)) continue;
    out.push({ json: {
      email:      m.email_address,
      first_name: m.merge_fields?.FNAME || '',
      last_name:  m.merge_fields?.LNAME || '',
      event_id:   ctx.event_id,
      event_name: ctx.event_name,
      session_id: ctx.session_id,
      grada_id:   ctx.grada_id,
      grada_name: ctx.grada_name,
      available:  ctx.available,
      purchase_url: ($('Vars').first().json.purchase_url_template || '')
        .replace('{sessionId}', String(ctx.session_id))
        .replace('{eventId}',   String(ctx.event_id))
        .replace('{gradaId}',   String(ctx.grada_id))
    }});
  }
}
return out;

const v = $('Vars').first().json;
const d = $input.item.json;
const fullName = (d.first_name + ' ' + d.last_name).trim() || d.email;
const subject = `¡Hay entradas en ${d.grada_name} para ${d.event_name}!`;
