const body = {
  key: v.mandrill_api_key,
  message: {
    from_email: v.mandrill_from_email,
    from_name:  v.mandrill_from_name,
    subject,
    to: [ { email: d.email, name: fullName, type: 'to' } ],
    html,
    tags: ['avisame', 'event-' + d.event_id, 'grada-' + d.grada_id],
    track_opens: true,
    track_clicks: true
  }
};
return { json: { mandrillBody: body, email: d.email, grada_name: d.grada_name } };
